---
import BaseLayout from './BaseLayout.astro';
import TopBar from '../components/TopBar.astro';
import { presetAtlas } from '../data/experiments';

interface Props {
  name: string;
  description?: string;
  appId?: string;
}

const { name, description, appId } = Astro.props;
const title = `${name} - incomplete.fun`;
const wallpaperGlyphs = [name, '∑', '∫', 'π', 'φ', 'λ', '∞', '⊕', '∂', '≈'].join(',');
---

<BaseLayout title={title} description={description}>
  <div class="canvas-app" id={appId}>
    <div class="equation-wallpaper" data-equation-wallpaper data-formulas={wallpaperGlyphs} aria-hidden="true"></div>
    <TopBar name={name} back>
      <slot name="toolbar" />
    </TopBar>
    <section class="control-panel" data-control-panel aria-label="Shared experiment controls">
      <button class="toolbar-button" type="button" data-control-action="pause">pause</button>
      <button class="toolbar-button" type="button" data-control-action="reset">reset</button>
      <button class="toolbar-button" type="button" data-control-action="randomize">randomize</button>
      <button class="toolbar-button" type="button" data-export-png>save png</button>
      <button class="toolbar-button" type="button" data-copy-url>copy url</button>
      <button class="toolbar-button" type="button" data-darkroom>darkroom</button>
      <label class="control-label">preset
        <select data-preset-atlas>
          <option value="">custom</option>
          {presetAtlas.map((preset) => <option value={preset}>{preset}</option>)}
        </select>
      </label>
      <label class="control-label">speed <input type="range" min="0" max="2" value="1" step="0.01" data-control-speed /></label>
      <slot name="controls" />
    </section>
    <aside class="math-notebook" aria-label="Math notebook">
      <strong>{name}</strong>
      <p>Definitions, examples, and nearby experiments live here as compact field notes while the canvas remains interactive.</p>
      <ul>
        <li><code>state</code>: current parameters and seed</li>
        <li><code>orbit</code>: repeated application of a rule</li>
        <li><a href="/">browse related experiments</a></li>
      </ul>
    </aside>
    <slot />
  </div>
</BaseLayout>

<script>
  import '../scripts/equation-wallpaper.ts';
  import '../scripts/unified-controls.ts';
  import '../scripts/preset-atlas.ts';
  import '../scripts/snapshot-export.ts';
  import '../scripts/darkroom.ts';
</script>

