import PageLayout from '../layouts/PageLayout.astro';
import { experiments } from '../data/experiments';
---

<PageLayout name="incomplete.fun" description="Small mathematical experiments, intentionally incomplete.">
  <section class="home-hero">
    <canvas class="landing-animation" data-landing-animation aria-hidden="true"></canvas>
    <p class="eyebrow">small experiments</p>
    <h1>mathematical toys, kept intentionally incomplete.</h1>
    <p class="home-intro">A quiet collection of visual calculators and playgrounds. Pick a thread and pull.</p>
  </section>

  <section class="constellation-map" aria-label="Experiment map">
    <svg viewBox="0 0 100 34" role="img">
      <title>Constellation map of experiments</title>
      {experiments.map((_, index) => {
        const x = 8 + (index % 8) * 12;
        const y = 6 + Math.floor(index / 8) * 11 + (index % 2) * 2;
        const nx = 8 + ((index + 1) % 8) * 12;
        const ny = 6 + Math.floor((index + 1) / 8) * 11 + ((index + 1) % 2) * 2;
        return <><line x1={x} y1={y} x2={nx} y2={ny} /><circle cx={x} cy={y} r="1.2" /></>;
      })}
    </svg>
  </section>

  <nav class="home-links" aria-label="Experiments">
    {experiments.map((experiment) => (
      <a class="home-link" href={experiment.href}>
        <canvas class="home-preview" data-preview-canvas={experiment.href} aria-hidden="true"></canvas>
        <span>{experiment.title}</span>
        <small>{experiment.summary}</small>
      </a>
    ))}
  </nav>
</PageLayout>

<script>
  import '../scripts/gallery-previews.ts';
  import '../scripts/landing-animation.ts';
</script>

